                [loading]="lazyLoading"
                [lazy]="true"
                (onLazyLoad)="onLazyLoad($event)"
                styleClass="border border-surface"
                [style]="{ width: '200px', height: '200px' }"
            >
                <ng-template #item let-item let-options="options">
