import { Component, OnInit, inject } from '@angular/core';
import { Table, TableModule } from 'primeng/table';
import { ProductService } from '@/service/productservice';
import { SortEvent } from 'primeng/api';
import { Product } from '@/domain/product';

@Component({
    template: `
        <p-table #dt [value]="products" (sortFunction)="customSort($event)" [customSort]="true">
            <ng-template #header>
                <tr>
                    <th pSortableColumn="code">
                        <div class="flex items-center gap-2">
                            Code
                            <p-sort-icon field="code" />
                        </div>
                    </th>
                    <th pSortableColumn="name">
                        <div class="flex items-center gap-2">
                            Name
                            <p-sort-icon field="name" />
                        </div>
                    </th>
                    <th pSortableColumn="category">
                        <div class="flex items-center gap-2">
                            Category
                            <p-sort-icon field="category" />
                        </div>
                    </th>
                    <th pSortableColumn="quantity">
                        <div class="flex items-center gap-2">
                            Quantity
                            <p-sort-icon field="quantity" />
                        </div>
                    </th>
                </tr>
            </ng-template>
            <ng-template #body let-product>
                <tr>
                    <td>{{ product.code }}</td>
                    <td>{{ product.name }}</td>
                    <td>{{ product.category }}</td>
                    <td>{{ product.quantity }}</td>
                </tr>
            </ng-template>
        </p-table>
    `,
    standalone: true,
    imports: [TableModule],
    providers: [ProductService]
})
export class TableRemovableSortDemo implements OnInit {
    private productService = inject(ProductService);
    products: Product[];
    initialValue: Product[];
    isSorted: boolean = null;

    ngOnInit() {
        this.productService.getProductsMini().then((data) => {
            this.products = data;
            this.initialValue = [...data];
        });
    }

    customSort(event: SortEvent) {
        if (this.isSorted == null || this.isSorted === undefined) {
            this.isSorted = true;
            this.sortTableData(event);
        } else if (this.isSorted == true) {
            this.isSorted = false;
            this.sortTableData(event);
        } else if (this.isSorted == false) {
            this.isSorted = null;
            this.products = [...this.initialValue];
            this.dt.reset();
        }
    }

    sortTableData(event) {
        event.data.sort((data1, data2) => {
            let value1 = data1[event.field];
            let value2 = data2[event.field];
            let result = null;
            if (value1 == null && value2 != null) result = -1;
            else if (value1 != null && value2 == null) result = 1;
            else if (value1 == null && value2 == null) result = 0;
            else if (typeof value1 === 'string' && typeof value2 === 'string') result = value1.localeCompare(value2);
            else result = value1 < value2 ? -1 : value1 > value2 ? 1 : 0;

            return event.order * result;
        });
    }
}

